import { writeFile } from "fs/promises";
import path from "path";
import { PDFDocument } from "pdf-lib";
import { createCanvas } from "canvas";
import Tesseract from "tesseract.js";
import * as pdfjsLib from "pdfjs-dist";


// Set worker path for PDF.js
pdfjsLib.GlobalWorkerOptions.workerSrc = `node_modules/pdfjs-dist/build/pdf.worker.js`;

const uploadDir = path.join(process.cwd(), "public/uploads");

export async function POST(req: Request) {
  try {
    const formData = await req.formData();
    const file = formData.get("file") as File;

    if (!file) {
      return new Response(JSON.stringify({ error: "No file uploaded" }), {
        status: 400,
      });
    }

    const filePath = path.join(uploadDir, file.name);
    const arrayBuffer = await file.arrayBuffer();
    await writeFile(filePath, Buffer.from(arrayBuffer));

    // Load PDF with pdf-lib
    const pdfDoc = await PDFDocument.load(Buffer.from(arrayBuffer));
    const firstPage = pdfDoc.getPage(0);

    // Convert PDF page to image using pdfjs-dist
    const pdfData = new Uint8Array(arrayBuffer);
    const loadingTask = pdfjsLib.getDocument({ data: pdfData });
    const pdf = await loadingTask.promise;
    const page = await pdf.getPage(1); // Get first page

    const viewport = page.getViewport({ scale: 2.0 }); // Adjust scale for resolution
    const canvas = createCanvas(viewport.width, viewport.height);
    const ctx = canvas.getContext("2d");

    const renderContext = {
      canvasContext: ctx,
      viewport: viewport,
    };

    await page.render(renderContext).promise;

    // Save canvas image
    const imagePath = path.join(uploadDir, "extracted_image.png");
    const buffer = canvas.toBuffer("image/png");
    await writeFile(imagePath, buffer);

    // Perform OCR using Tesseract.js
    const {
      data: { text },
    } = await Tesseract.recognize(imagePath, "eng");

    return new Response(JSON.stringify({ text }), { status: 200 });
  } catch (error) {
    return new Response(JSON.stringify({ error: error.message }), {
      status: 500,
    });
  }
}
